1	import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
2	import { RouterProvider } from "react-router-dom";
3	import { SessionProvider } from "@/features/session/context";
4	import { router } from "./router";
5	import { routerFuture } from "./routerFuture";
6	import type { ReactNode } from "react";
7	
8	const queryClient = new QueryClient({
9	  defaultOptions: {
10	    queries: {
11	      staleTime: 2000,
12	      retry: 1,
13	    },
14	  },
15	});
16	
17	export function Providers({ children }: { children?: ReactNode }) {
18	  return (
19	    <QueryClientProvider client={queryClient}>
20	      <SessionProvider>
21	        {children ?? <RouterProvider router={router} future={routerFuture} />}
