1	import { createContext, useContext, useState, useCallback, type ReactNode } from "react";
2	
3	export interface Assumption {
4	  variableId: string;
5	  outcomeId: string;
6	  /** Display label for the assumption */
7	  label: string;
8	}
9	
10	interface AssumptionState {
11	  assumptions: Assumption[];
12	  addAssumption: (a: Assumption) => void;
13	  removeAssumption: (variableId: string) => void;
14	  clearAll: () => void;
15	  hasAssumption: (variableId: string) => boolean;
16	  getAssumption: (variableId: string) => Assumption | undefined;
17	  /** Context array for API calls */
18	  contextPayload: Array<{ variableId: string; outcomeId: string }>;
19	}
20	
21	const AssumptionCtx = createContext<AssumptionState | null>(null);
22	
23	export function AssumptionProvider({ children }: { children: ReactNode }) {
24	  const [assumptions, setAssumptions] = useState<Assumption[]>([]);
25	
26	  const addAssumption = useCallback((a: Assumption) => {
27	    setAssumptions((prev) => {
28	      const filtered = prev.filter((p) => p.variableId !== a.variableId);
29	      return [...filtered, a];
30	    });
31	  }, []);
32	
33	  const removeAssumption = useCallback((variableId: string) => {
34	    setAssumptions((prev) => prev.filter((p) => p.variableId !== variableId));
35	  }, []);
36	
37	  const clearAll = useCallback(() => setAssumptions([]), []);
38	
39	  const hasAssumption = useCallback(
40	    (variableId: string) => assumptions.some((a) => a.variableId === variableId),
41	    [assumptions],
42	  );
43	
44	  const getAssumption = useCallback(
45	    (variableId: string) => assumptions.find((a) => a.variableId === variableId),
46	    [assumptions],
47	  );
48	
49	  const contextPayload = assumptions.map((a) => ({
50	    variableId: a.variableId,
51	    outcomeId: a.outcomeId,
52	  }));
53	
54	  return (
55	    <AssumptionCtx.Provider
56	      value={{ assumptions, addAssumption, removeAssumption, clearAll, hasAssumption, getAssumption, contextPayload }}
57	    >
58	      {children}
59	    </AssumptionCtx.Provider>
60	  );
61	}
62	
63	export function useAssumptions() {
64	  const ctx = useContext(AssumptionCtx);
65	  if (!ctx) throw new Error("useAssumptions must be used within AssumptionProvider");
66	  return ctx;
67	}
