97	function PositionCard({
98	  marketId,
99	  accountRisk,
100	  isConfigured,
101	}: {
102	  marketId: string;
103	  accountRisk: import("@/lib/api/types").AccountRiskResponse | undefined;
104	  isConfigured: boolean;
105	}) {
106	  if (!isConfigured || !accountRisk) return null;
107	
108	  const marketRisk = accountRisk.account.risk.minAssets.markets.find(
109	    (mr) => mr.marketId === marketId,
110	  );
111	
112	  if (!marketRisk) return null;
113	
114	  const utilColor = marketRisk.utilization > 0.8
115	    ? "var(--color-danger)"
116	    : marketRisk.utilization > 0.5
117	      ? "var(--color-warning, orange)"
118	      : "var(--color-text)";
119	
120	  return (
121	    <div style={positionCardStyle}>
122	      <div style={{ fontSize: "0.8rem", fontWeight: 600, marginBottom: "var(--space-xs)" }}>
123	        Your Position
124	      </div>
125	      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "var(--space-sm)", fontSize: "0.8rem" }}>
126	        <div>
127	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Min Asset</div>
128	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600 }}>{marketRisk.minAsset.toFixed(2)}</div>
129	        </div>
130	        <div>
131	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Utilization</div>
132	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600, color: utilColor }}>
133	            {(marketRisk.utilization * 100).toFixed(1)}%
134	          </div>
135	        </div>
136	        <div>
137	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Trades</div>
